#include <bits/stdc++.h>

using namespace std;



int arr[10];



bool check(int num) {

    while(num) {

        if(arr[num%10])

            return false;

        num/=10;

    }

    return true;

}



int main()

{

    int n,k;

    int x;

    scanf("%d%d",&n,&k);

    for(int i = 0; i < k; i++) {

        scanf("%d",&x);

        arr[x] = 1;

    }

    while(!check(n)) {

        n++;

    }

    printf("%d",n);

    return 0;

}

