using namespace std;



int main()

{

    int64_t N, K;

    std::cin >> N >> K;



    std::string D;

    D = "[";

    for (size_t i = 0; i < K; ++i) {

        char t;

        std::cin >> t;

        D += t;

    }

    D += "]";



    cerr << D << endl;



    std::regex re(D);

    for (;;) {

        auto s = boost::lexical_cast<std::string>(N);

        if (!std::regex_search(s, re)) {

            std::cout << s << std::endl;

            return 0;

        }

        N++;

    }





    return 0;

}

